/**
 * Summarization engine for md-tldr
 *
 * Provides hierarchical summarization and multi-document context assembly
 */

import * as fs from 'node:fs/promises'
import * as path from 'node:path'
import { Effect } from 'effect'
import type { MdDocument, MdSection } from '../core/types.js'
import { parseFile } from '../parser/parser.js'
import { countTokensApprox } from '../utils/tokens.js'
import { formatSummary as formatSummaryImpl } from './formatters.js'

// ============================================================================
// Types
// ============================================================================

export type CompressionLevel = 'brief' | 'summary' | 'full'

export interface SummarizeOptions {
  /** Compression level */
  readonly level?: CompressionLevel | undefined
  /** Maximum tokens for output */
  readonly maxTokens?: number | undefined
}

export interface SectionSummary {
  readonly heading: string
  readonly level: number
  readonly originalTokens: number
  readonly summaryTokens: number
  readonly summary: string
  readonly children: readonly SectionSummary[]
  readonly hasCode: boolean
  readonly hasList: boolean
  readonly hasTable: boolean
}

export interface DocumentSummary {
  readonly path: string
  readonly title: string
  readonly originalTokens: number
  readonly summaryTokens: number
  readonly compressionRatio: number
  readonly sections: readonly SectionSummary[]
  readonly keyTopics: readonly string[]
  /** True if content was truncated to fit budget */
  readonly truncated?: boolean
  /** Number of sections that were omitted due to budget constraints */
  readonly truncatedCount?: number
}

export interface AssembleContextOptions {
  /** Total token budget */
  readonly budget: number
  /** Compression level for each source */
  readonly level?: CompressionLevel | undefined
}

export interface AssembledContext {
  readonly sources: readonly SourceContext[]
  readonly totalTokens: number
  readonly budget: number
  readonly overflow: readonly string[]
}

export interface SourceContext {
  readonly path: string
  readonly title: string
  readonly tokens: number
  readonly content: string
}

// ============================================================================
// Constants
// ============================================================================

/** Token budgets per compression level */
const TOKEN_BUDGETS: Record<CompressionLevel, number> = {
  brief: 100,
  summary: 500,
  full: Infinity,
}

/** Minimum character length for a sentence to be considered meaningful */
const MIN_SENTENCE_LENGTH = 10

/** Score weights for sentence importance heuristics */
const SENTENCE_SCORE_DEFINITION = 2 // sentences with colons (definitions)
const SENTENCE_SCORE_PROPER_START = 1 // sentences starting with capital
const SENTENCE_SCORE_MEDIUM_LENGTH = 1 // sentences in ideal length range
const SENTENCE_SCORE_EMPHASIS = 1 // sentences with emphasis or code

/** Ideal sentence length range for summaries */
const SENTENCE_LENGTH_MIN = 50
const SENTENCE_LENGTH_MAX = 200

/** Target compression ratio for summaries (30% of original) */
const SUMMARY_COMPRESSION_RATIO = 0.3

/** Minimum tokens for any section summary */
const MIN_SECTION_TOKENS = 20

/** Minimum sentences to include in any summary */
const MIN_SUMMARY_SENTENCES = 2

/** Approximate tokens per sentence (for calculating max sentences) */
const TOKENS_PER_SENTENCE_ESTIMATE = 30

/** Topic heading length constraints */
const MIN_TOPIC_LENGTH = 2
const MAX_TOPIC_LENGTH = 50

/** Maximum topics to extract from a document */
const MAX_TOPICS = 10

/** Minimum remaining budget to include partial content */
const MIN_PARTIAL_BUDGET = 50

// ============================================================================
// Section Summarization
// ============================================================================

const extractKeyPoints = (content: string, maxSentences: number): string[] => {
  // Split into sentences
  const sentences = content
    .replace(/\n+/g, ' ')
    .split(/(?<=[.!?])\s+/)
    .filter((s) => s.trim().length > MIN_SENTENCE_LENGTH)

  if (sentences.length <= maxSentences) {
    return sentences
  }

  // Simple heuristic: prefer sentences with key indicators
  const scored = sentences.map((s) => {
    let score = 0
    // Prefer sentences with:
    if (s.includes(':')) score += SENTENCE_SCORE_DEFINITION
    if (/^[A-Z]/.test(s)) score += SENTENCE_SCORE_PROPER_START
    if (s.length > SENTENCE_LENGTH_MIN && s.length < SENTENCE_LENGTH_MAX)
      score += SENTENCE_SCORE_MEDIUM_LENGTH
    if (/\*\*|`/.test(s)) score += SENTENCE_SCORE_EMPHASIS
    return { sentence: s, score }
  })

  // Sort by score and take top sentences
  scored.sort((a, b) => b.score - a.score)
  return scored.slice(0, maxSentences).map((s) => s.sentence)
}

const summarizeSection = (
  section: MdSection,
  level: CompressionLevel,
): SectionSummary => {
  const originalTokens = section.metadata.tokenCount

  // Get children summaries first
  const children = section.children.map((child) =>
    summarizeSection(child, level),
  )

  // Calculate target tokens based on level
  const targetTokens = Math.min(
    TOKEN_BUDGETS[level],
    Math.max(originalTokens * SUMMARY_COMPRESSION_RATIO, MIN_SECTION_TOKENS),
  )

  let summary: string

  if (level === 'full' || originalTokens <= targetTokens) {
    // Include full content for "full" level or if already small
    // Use plainText instead of content to avoid including the heading markdown
    // (the heading is output separately by the formatter)
    summary = section.plainText
  } else if (level === 'brief') {
    // Just heading and metadata for brief
    const meta: string[] = []
    if (section.metadata.hasCode) meta.push('code')
    if (section.metadata.hasList) meta.push('list')
    if (section.metadata.hasTable) meta.push('table')
    summary = meta.length > 0 ? `[${meta.join(', ')}]` : ''
  } else {
    // Summary level: extract key points
    const maxSentences = Math.max(
      MIN_SUMMARY_SENTENCES,
      Math.floor(targetTokens / TOKENS_PER_SENTENCE_ESTIMATE),
    )
    const keyPoints = extractKeyPoints(section.plainText, maxSentences)

    if (keyPoints.length > 0) {
      summary = keyPoints.join(' ')
    } else {
      // Fallback: truncate
      const words = section.plainText.split(/\s+/).slice(0, targetTokens)
      summary =
        words.join(' ') +
        (words.length < section.plainText.split(/\s+/).length ? '...' : '')
    }
  }

  const summaryTokens = countTokensApprox(summary)

  return {
    heading: section.heading,
    level: section.level,
    originalTokens,
    summaryTokens,
    summary,
    children,
    hasCode: section.metadata.hasCode,
    hasList: section.metadata.hasList,
    hasTable: section.metadata.hasTable,
  }
}

// ============================================================================
// Document Summarization
// ============================================================================

const extractTopics = (document: MdDocument): string[] => {
  const topics: Set<string> = new Set()

  // Extract from headings
  const processSection = (section: MdSection) => {
    // Clean heading and add as topic
    const cleanHeading = section.heading
      .replace(/[:#\-_]/g, ' ')
      .trim()
      .toLowerCase()
    if (
      cleanHeading.length > MIN_TOPIC_LENGTH &&
      cleanHeading.length < MAX_TOPIC_LENGTH
    ) {
      topics.add(cleanHeading)
    }

    for (const child of section.children) {
      processSection(child)
    }
  }

  for (const section of document.sections) {
    processSection(section)
  }

  // Also extract from frontmatter tags if present
  const frontmatter = document.frontmatter as Record<string, unknown>
  if (frontmatter.tags && Array.isArray(frontmatter.tags)) {
    for (const tag of frontmatter.tags) {
      if (typeof tag === 'string') {
        topics.add(tag.toLowerCase())
      }
    }
  }

  return Array.from(topics).slice(0, MAX_TOPICS)
}

export const summarizeDocument = (
  document: MdDocument,
  options: SummarizeOptions = {},
): DocumentSummary => {
  const level = options.level ?? 'summary'
  const maxTokens = options.maxTokens ?? TOKEN_BUDGETS[level]

  // Summarize all sections
  const allSections = document.sections.map((s) => summarizeSection(s, level))

  // Calculate totals and collect all flattened sections with their tokens
  const originalTokens = document.metadata.tokenCount
  let totalSummaryTokens = 0
  const flatSections: SectionSummary[] = []

  const flattenWithTokens = (section: SectionSummary) => {
    flatSections.push(section)
    totalSummaryTokens += section.summaryTokens
    for (const child of section.children) {
      flattenWithTokens(child)
    }
  }

  for (const section of allSections) {
    flattenWithTokens(section)
  }

  // Calculate formatting overhead dynamically based on actual content
  // Header includes: "# {title}\nPath: {path}\nTokens: X (Y% reduction from Z)\n"
  // Plus topics line if present, plus possible truncation warning
  const topics = extractTopics(document)
  const headerTemplate = `# ${document.title}\nPath: ${document.path}\nTokens: 9999 (99% reduction from ${document.metadata.tokenCount})\n`
  const topicsLine =
    topics.length > 0 ? `\n**Topics:** ${topics.join(', ')}\n` : ''
  const truncationWarning =
    '\n⚠️ TRUNCATED: 999 sections omitted to fit token budget'
  // Add all possible overhead plus a generous safety margin (20% of overhead + 20 base)
  // This accounts for variance in token estimation
  const baseOverhead = countTokensApprox(
    headerTemplate + topicsLine + truncationWarning,
  )
  const formattingOverhead = Math.ceil(baseOverhead * 1.2) + 20
  const contentBudget = maxTokens - formattingOverhead

  // If over budget, truncate sections to fit
  let truncated = false
  let truncatedCount = 0
  let sections: SectionSummary[]
  let summaryTokens: number

  if (totalSummaryTokens > contentBudget && contentBudget > 0) {
    // Need to truncate - use greedy tree traversal that can include children
    // even when parent doesn't fit (orphan rescue)
    let tokensUsed = 0

    // Process tree with orphan rescue: if parent doesn't fit, still try children
    const truncateSections = (
      sectionList: readonly SectionSummary[],
    ): SectionSummary[] => {
      const result: SectionSummary[] = []

      for (const section of sectionList) {
        const sectionOwnTokens = section.summaryTokens
        const fitsInBudget = tokensUsed + sectionOwnTokens <= contentBudget

        if (fitsInBudget) {
          // Section fits - include it and recursively process children
          tokensUsed += sectionOwnTokens
          const truncatedChildren = truncateSections(section.children)
          result.push({
            ...section,
            children: truncatedChildren,
          })
        } else {
          // Section doesn't fit - but still try to rescue children (orphan rescue)
          truncatedCount++
          const rescuedChildren = truncateSections(section.children)
          // Add rescued children as top-level items in result
          result.push(...rescuedChildren)
        }
      }

      return result
    }

    sections = truncateSections(allSections)
    summaryTokens = tokensUsed
    truncated = truncatedCount > 0
  } else {
    sections = allSections
    summaryTokens = totalSummaryTokens
  }

  const compressionRatio =
    originalTokens > 0 ? 1 - summaryTokens / originalTokens : 0

  const result: DocumentSummary = {
    path: document.path,
    title: document.title,
    originalTokens,
    summaryTokens,
    compressionRatio,
    sections,
    keyTopics: topics,
  }

  if (truncated) {
    return {
      ...result,
      truncated: true,
      truncatedCount,
    }
  }

  return result
}

export const summarizeFile = (
  filePath: string,
  options: SummarizeOptions = {},
): Effect.Effect<DocumentSummary, Error> =>
  Effect.gen(function* () {
    const document = yield* parseFile(filePath).pipe(
      Effect.mapError((e) => new Error(`${e._tag}: ${e.message}`)),
    )

    return summarizeDocument(document, options)
  })

// ============================================================================
// Format Summary for Output (re-exported from formatters.ts)
// ============================================================================

export { formatSummary, type FormatSummaryOptions } from './formatters.js'

// ============================================================================
// Multi-Document Context Assembly
// ============================================================================

export const assembleContext = (
  rootPath: string,
  sourcePaths: readonly string[],
  options: AssembleContextOptions,
): Effect.Effect<AssembledContext, Error> =>
  Effect.gen(function* () {
    const budget = options.budget
    const level = options.level ?? 'summary'

    const sources: SourceContext[] = []
    const overflow: string[] = []
    let totalTokens = 0

    // Calculate per-source budget (even distribution)
    const perSourceBudget = Math.floor(budget / sourcePaths.length)

    for (const sourcePath of sourcePaths) {
      const resolvedPath = path.isAbsolute(sourcePath)
        ? sourcePath
        : path.join(rootPath, sourcePath)

      try {
        const summary = yield* summarizeFile(resolvedPath, {
          level,
          maxTokens: perSourceBudget,
        })

        const content = formatSummaryImpl(summary)
        // Count actual formatted output tokens, not pre-format summary tokens
        const tokens = countTokensApprox(content)

        if (totalTokens + tokens <= budget) {
          sources.push({
            path: path.relative(rootPath, resolvedPath),
            title: summary.title,
            tokens,
            content,
          })
          totalTokens += tokens
        } else {
          // Over budget
          const remaining = budget - totalTokens
          if (remaining > MIN_PARTIAL_BUDGET) {
            // Include partial if we have some room
            const briefSummary = yield* summarizeFile(resolvedPath, {
              level: 'brief',
              maxTokens: remaining,
            })
            const briefContent = formatSummaryImpl(briefSummary)
            // Count actual formatted output tokens, not pre-format summary tokens
            const briefTokens = countTokensApprox(briefContent)

            sources.push({
              path: path.relative(rootPath, resolvedPath),
              title: briefSummary.title,
              tokens: briefTokens,
              content: briefContent,
            })
            totalTokens += briefTokens
          } else {
            overflow.push(path.relative(rootPath, resolvedPath))
          }
        }
      } catch (_e) {
        // Skip files that can't be processed
        overflow.push(sourcePath)
      }
    }

    return {
      sources,
      totalTokens,
      budget,
      overflow,
    }
  })

// ============================================================================
// Format Assembled Context (re-exported from formatters.ts)
// ============================================================================

export { formatAssembledContext } from './formatters.js'

// ============================================================================
// Measure Token Reduction
// ============================================================================

export interface TokenReductionReport {
  readonly originalTokens: number
  readonly summaryTokens: number
  readonly reduction: number
  readonly reductionPercent: number
}

export const measureReduction = async (
  filePath: string,
  level: CompressionLevel = 'summary',
): Promise<TokenReductionReport> => {
  // Read original content
  const originalContent = await fs.readFile(filePath, 'utf-8')
  const originalTokens = countTokensApprox(originalContent)

  // Get summary
  const result = await Effect.runPromise(
    summarizeFile(filePath, { level }).pipe(
      Effect.catchAll(() => Effect.succeed(null)),
    ),
  )

  if (!result) {
    return {
      originalTokens,
      summaryTokens: originalTokens,
      reduction: 0,
      reductionPercent: 0,
    }
  }

  const summaryTokens = result.summaryTokens
  const reduction = originalTokens - summaryTokens
  const reductionPercent = originalTokens > 0 ? reduction / originalTokens : 0

  return {
    originalTokens,
    summaryTokens,
    reduction,
    reductionPercent,
  }
}

/**
 * Formatting functions for summarization output
 *
 * Responsible for converting summary data structures into human-readable text
 */

import { countTokensApprox } from '../utils/tokens.js'
import type {
  AssembledContext,
  DocumentSummary,
  SectionSummary,
} from './summarizer.js'

export interface FormatSummaryOptions {
  /** Maximum tokens for formatted output. If exceeded, sections will be truncated. */
  readonly maxTokens?: number
}

/**
 * Format a document summary for display
 *
 * Outputs a markdown-formatted summary with:
 * - Title and path
 * - Accurate token count (of the formatted output)
 * - Key topics
 * - Hierarchical section summaries
 *
 * When maxTokens is specified, strictly enforces the budget by iteratively
 * removing sections until the output fits.
 */
export const formatSummary = (
  summary: DocumentSummary,
  options: FormatSummaryOptions = {},
): string => {
  const maxTokens = options.maxTokens

  // Flatten sections in order for incremental building
  // Uses depth-first order so children follow parents - this enables "orphan rescue"
  // where children can still be included even if their parent was too large
  const flatSections: { section: SectionSummary; depth: number }[] = []

  const collectSections = (section: SectionSummary, depth: number = 0) => {
    flatSections.push({ section, depth })
    for (const child of section.children) {
      collectSections(child, depth + 1)
    }
  }

  for (const section of summary.sections) {
    collectSections(section)
  }

  // Helper to build output with a given set of section indices
  const buildOutput = (
    includedSectionIndices: Set<number>,
    showTruncationWarning: boolean,
    truncationCount: number,
    includeTopics: boolean,
  ): string => {
    const lines: string[] = []
    lines.push(`# ${summary.title}`)
    lines.push(`Path: ${summary.path}`)

    // Placeholder for token line - we'll calculate actual tokens after building
    const tokenLineIndex = lines.length
    lines.push('PLACEHOLDER')

    if (showTruncationWarning && truncationCount > 0) {
      const totalTruncated = truncationCount + (summary.truncatedCount ?? 0)
      lines.push(
        `⚠️ TRUNCATED: ${totalTruncated} sections omitted to fit token budget`,
      )
    }
    lines.push('')

    const fullTopicsLine =
      summary.keyTopics.length > 0
        ? `**Topics:** ${summary.keyTopics.join(', ')}`
        : ''

    if (includeTopics && fullTopicsLine) {
      lines.push(fullTopicsLine)
      lines.push('')
    }

    // Build section content
    const sectionLines: string[] = []
    for (let i = 0; i < flatSections.length; i++) {
      if (!includedSectionIndices.has(i)) continue
      const { section, depth } = flatSections[i]!
      const indent = '  '.repeat(depth)
      const prefix = '#'.repeat(section.level)
      sectionLines.push(`${indent}${prefix} ${section.heading}`)
      if (section.summary) {
        sectionLines.push(`${indent}${section.summary}`)
      }
    }

    lines.push(sectionLines.join('\n'))

    // Calculate actual token count for this output
    // Build output without token line first
    const tempOutput = lines.join('\n')
    const tokensWithoutLine = countTokensApprox(
      tempOutput.replace('PLACEHOLDER', ''),
    )

    // The token line itself adds tokens - iterate to find stable count
    // Token line format: "Tokens: XXX (YY% reduction from ZZZ)"
    let estimatedTotal = tokensWithoutLine + 8 // Initial estimate for token line
    for (let iter = 0; iter < 3; iter++) {
      const testTokenLine = `Tokens: ${estimatedTotal} (${(summary.compressionRatio * 100).toFixed(0)}% reduction from ${summary.originalTokens})`
      const testOutput = tempOutput.replace('PLACEHOLDER', testTokenLine)
      const actualTotal = countTokensApprox(testOutput)
      if (actualTotal === estimatedTotal) break
      estimatedTotal = actualTotal
    }

    // Final token line with converged count
    const finalTokenLine = `Tokens: ${estimatedTotal} (${(summary.compressionRatio * 100).toFixed(0)}% reduction from ${summary.originalTokens})`
    lines[tokenLineIndex] = finalTokenLine

    return lines.join('\n')
  }

  // If no budget, include everything
  if (maxTokens === undefined) {
    const allIndices = new Set(flatSections.map((_, i) => i))
    const hasPriorTruncation = summary.truncated && summary.truncatedCount
    return buildOutput(allIndices, !!hasPriorTruncation, 0, true)
  }

  // With budget: greedily add sections, then validate and trim if needed
  const includedIndices = new Set<number>()
  let truncatedCount = 0
  let includeTopics = true

  // First pass: estimate what fits using conservative token counting
  // Add 15% safety margin to each section's token count
  const SAFETY_MARGIN = 1.15

  // Calculate minimum header overhead (title, path, token line)
  const minHeaderTemplate = [
    `# ${summary.title}`,
    `Path: ${summary.path}`,
    `Tokens: 9999 (${(summary.compressionRatio * 100).toFixed(0)}% reduction from ${summary.originalTokens})`,
    '',
    '',
  ].join('\n')
  const minHeaderTokens = Math.ceil(
    countTokensApprox(minHeaderTemplate) * SAFETY_MARGIN,
  )

  // Calculate topics overhead
  const fullTopicsLine =
    summary.keyTopics.length > 0
      ? `**Topics:** ${summary.keyTopics.join(', ')}\n`
      : ''
  const topicsTokens = fullTopicsLine
    ? Math.ceil(countTokensApprox(fullTopicsLine) * SAFETY_MARGIN)
    : 0

  // Truncation warning overhead
  const truncationWarningTokens = Math.ceil(
    countTokensApprox(
      `⚠️ TRUNCATED: 999 sections omitted to fit token budget\n`,
    ) * SAFETY_MARGIN,
  )

  // Start with header + topics
  let headerTokens = minHeaderTokens + topicsTokens

  // If header alone exceeds budget, drop topics
  if (headerTokens >= maxTokens) {
    includeTopics = false
    headerTokens = minHeaderTokens
  }

  // Calculate content budget (reserve space for potential truncation warning)
  let contentBudget = maxTokens - headerTokens - truncationWarningTokens
  let tokensUsed = 0

  // Greedy section selection
  for (let i = 0; i < flatSections.length; i++) {
    const { section, depth } = flatSections[i]!
    const indent = '  '.repeat(depth)
    const prefix = '#'.repeat(section.level)
    const sectionContent = section.summary
      ? `${indent}${prefix} ${section.heading}\n${indent}${section.summary}`
      : `${indent}${prefix} ${section.heading}`

    const sectionTokens = Math.ceil(
      countTokensApprox(sectionContent) * SAFETY_MARGIN,
    )

    if (tokensUsed + sectionTokens <= contentBudget) {
      includedIndices.add(i)
      tokensUsed += sectionTokens
    } else {
      truncatedCount++
    }
  }

  // If nothing was truncated, we can use the full content budget
  if (truncatedCount === 0) {
    contentBudget += truncationWarningTokens
  }

  // Build output and validate it fits
  let output = buildOutput(
    includedIndices,
    truncatedCount > 0,
    truncatedCount,
    includeTopics,
  )
  let actualTokens = countTokensApprox(output)

  // Final validation loop: remove sections from the end until we fit
  // This handles any estimation errors
  const sortedIndices = Array.from(includedIndices).sort((a, b) => b - a) // Reverse order
  let removalIndex = 0

  while (actualTokens > maxTokens && removalIndex < sortedIndices.length) {
    // Remove the last section
    const indexToRemove = sortedIndices[removalIndex]!
    includedIndices.delete(indexToRemove)
    truncatedCount++
    removalIndex++

    // Rebuild and recheck
    output = buildOutput(includedIndices, true, truncatedCount, includeTopics)
    actualTokens = countTokensApprox(output)
  }

  // If still over budget and we haven't dropped topics yet, try that
  if (actualTokens > maxTokens && includeTopics) {
    includeTopics = false
    output = buildOutput(includedIndices, true, truncatedCount, includeTopics)
    actualTokens = countTokensApprox(output)
  }

  // If still over budget, try dropping the truncation warning as last resort
  // (only if we're showing it and have truncated sections)
  if (actualTokens > maxTokens && truncatedCount > 0) {
    output = buildOutput(includedIndices, false, truncatedCount, includeTopics)
    actualTokens = countTokensApprox(output)
  }

  return output
}

/**
 * Format assembled context for display
 *
 * Outputs a combined view of multiple document summaries with:
 * - Header showing total tokens and source count
 * - Individual source summaries separated by dividers
 * - Overflow list for sources that didn't fit the budget
 */
export const formatAssembledContext = (context: AssembledContext): string => {
  const lines: string[] = []

  lines.push('# Context Assembly')
  lines.push(`Total tokens: ${context.totalTokens}/${context.budget}`)
  lines.push(`Sources: ${context.sources.length}`)
  lines.push('')

  for (const source of context.sources) {
    lines.push('---')
    lines.push('')
    lines.push(source.content)
  }

  if (context.overflow.length > 0) {
    lines.push('---')
    lines.push('')
    lines.push('## Overflow (not included due to budget)')
    for (const overflowPath of context.overflow) {
      lines.push(`- ${overflowPath}`)
    }
  }

  return lines.join('\n')
}

/**
 * Token counting utilities using tiktoken
 */

import { Effect } from 'effect'

// Lazy-loaded tiktoken encoder
let encoder: Awaited<
  ReturnType<typeof import('tiktoken').get_encoding>
> | null = null

const getEncoder = Effect.gen(function* () {
  if (encoder === null) {
    const { get_encoding } = yield* Effect.promise(() => import('tiktoken'))
    encoder = get_encoding('cl100k_base')
  }
  return encoder
})

/**
 * Count tokens in a string using the cl100k_base encoding
 * (compatible with GPT-4, GPT-3.5-turbo, and Claude models)
 */
export const countTokens = (
  text: string,
): Effect.Effect<number, never, never> =>
  Effect.gen(function* () {
    const enc = yield* getEncoder
    const tokens = enc.encode(text)
    return tokens.length
  })

/**
 * Synchronous token counting with improved approximation
 *
 * Uses heuristics calibrated against cl100k_base encoding:
 * - Base: ~4.4 chars/token for ASCII prose (calibrated against actual tokenizer)
 * - Code blocks: ~3.8 chars/token (similar to prose but with more symbols)
 * - Inline code: ~2.5 chars/token (backticks tokenize separately)
 * - Paths: ~3.5 chars/token (slashes tokenize separately)
 * - Punctuation: adds ~0.5 tokens per mark (often become separate tokens)
 * - CJK characters: ~1 token per character (they tokenize individually)
 * - Emojis: ~2 tokens per emoji (often split into multiple tokens)
 *
 * Safety margin of 10% to handle edge cases while avoiding over-estimation.
 */
export const countTokensApprox = (text: string): number => {
  if (text.length === 0) return 0

  // Count CJK characters (Chinese, Japanese, Korean)
  // These typically tokenize to 1-2 tokens per character
  // Unicode ranges: CJK Unified Ideographs, Hiragana, Katakana, Hangul
  const cjkPattern =
    /[\u4e00-\u9fff\u3040-\u309f\u30a0-\u30ff\uac00-\ud7af\u3400-\u4dbf]/g
  const cjkMatches = text.match(cjkPattern) || []
  const cjkCount = cjkMatches.length

  // Count emojis and symbols (they often tokenize to 2-4 tokens each)
  // This pattern catches most common emojis, symbols, and dingbats
  // Also count variation selectors (FE0E/FE0F) which add extra tokens
  const emojiPattern =
    /[\u{1F300}-\u{1F9FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}\u{1F600}-\u{1F64F}\u{1F680}-\u{1F6FF}\u{2300}-\u{23FF}\u{2190}-\u{21FF}\u{25A0}-\u{25FF}\u{2B00}-\u{2BFF}]/gu
  const emojiMatches = text.match(emojiPattern) || []
  const emojiCount = emojiMatches.length

  // Count variation selectors (they add extra tokens to base characters)
  const variationSelectorPattern = /[\uFE0E\uFE0F]/g
  const variationMatches = text.match(variationSelectorPattern) || []
  const variationCount = variationMatches.length

  // First, remove code blocks and replace with placeholder to avoid double-counting
  // We'll process them separately
  let workingText = text
  const codeBlockMatches = text.match(/```[\s\S]*?```/g) || []
  const codeBlockLength = codeBlockMatches.reduce((sum, m) => sum + m.length, 0)

  // Remove code blocks from working text for inline code detection
  for (const match of codeBlockMatches) {
    workingText = workingText.replace(match, '')
  }

  // Extract inline code from the remaining text (single backticks)
  const inlineCodeMatches = workingText.match(/`[^`]+`/g) || []
  const inlineCodeLength = inlineCodeMatches.reduce(
    (sum, m) => sum + m.length,
    0,
  )

  // Remaining text (prose) is original length minus code blocks and inline code
  const proseLength = text.length - codeBlockLength - inlineCodeLength

  // Count path-like sequences in prose (consecutive /word patterns)
  // Remove inline code from working text first
  for (const match of inlineCodeMatches) {
    workingText = workingText.replace(match, '')
  }
  const pathMatches = workingText.match(/(?:\/[\w.-]+)+/g) || []
  const pathLength = pathMatches.reduce((sum, m) => sum + m.length, 0)

  // For prose, we need to subtract CJK, emoji, and variation characters since they're counted separately
  const adjustedProseLength = Math.max(
    0,
    proseLength - pathLength - cjkCount - emojiCount - variationCount,
  )

  // Count punctuation in prose (outside code) - these often become separate tokens
  const punctuationMatches =
    workingText.match(/[!?,.:;'"()[\]{}@#$%^&*+=|\\<>~-]/g) || []
  const punctuationCount = punctuationMatches.length

  // Estimate tokens with calibrated ratios:
  // - ASCII prose: ~4.4 chars/token (base rate)
  // - Code blocks: ~3.8 chars/token
  // - Inline code: ~2.5 chars/token (backticks are separate tokens)
  // - Paths: ~3.5 chars/token (slashes are separate tokens)
  // - Punctuation bonus: ~0.5 tokens per punctuation mark
  // - CJK: ~1.2 tokens per character (conservative estimate)
  // - Emojis: ~2.5 tokens per emoji (conservative for compound emojis)
  // - Variation selectors: ~1 token each
  const proseTokens = adjustedProseLength / 4.4
  const codeBlockTokens = codeBlockLength / 3.8
  const inlineCodeTokens = inlineCodeLength / 2.5
  const pathTokens = pathLength / 3.5
  const punctuationBonus = punctuationCount * 0.5
  const cjkTokens = cjkCount * 1.2
  const emojiTokens = emojiCount * 2.5
  const variationTokens = variationCount * 1

  const estimate =
    proseTokens +
    codeBlockTokens +
    inlineCodeTokens +
    pathTokens +
    punctuationBonus +
    cjkTokens +
    emojiTokens +
    variationTokens

  // Add 10% safety margin to avoid under-counting
  return Math.ceil(estimate * 1.1)
}

/**
 * Count words in text
 */
export const countWords = (text: string): number => {
  const trimmed = text.trim()
  if (trimmed.length === 0) return 0
  return trimmed.split(/\s+/).length
}

