/**
 * Synchronous token counting with improved approximation
 *
 * Uses heuristics calibrated against cl100k_base encoding:
 * - Base: ~4.4 chars/token for ASCII prose (calibrated against actual tokenizer)
 * - Code blocks: ~3.8 chars/token (similar to prose but with more symbols)
 * - Inline code: ~2.5 chars/token (backticks tokenize separately)
 * - Paths: ~3.5 chars/token (slashes tokenize separately)
 * - Punctuation: adds ~0.5 tokens per mark (often become separate tokens)
 * - CJK characters: ~1 token per character (they tokenize individually)
 * - Emojis: ~2 tokens per emoji (often split into multiple tokens)
 *
 * Safety margin of 10% to handle edge cases while avoiding over-estimation.
 */
export const countTokensApprox = (text: string): number => {
  if (text.length === 0) return 0

  // Count CJK characters (Chinese, Japanese, Korean)
  // These typically tokenize to 1-2 tokens per character
  // Unicode ranges: CJK Unified Ideographs, Hiragana, Katakana, Hangul
  const cjkPattern =
    /[\u4e00-\u9fff\u3040-\u309f\u30a0-\u30ff\uac00-\ud7af\u3400-\u4dbf]/g
  const cjkMatches = text.match(cjkPattern) || []
  const cjkCount = cjkMatches.length

  // Count emojis and symbols (they often tokenize to 2-4 tokens each)
  // This pattern catches most common emojis, symbols, and dingbats
  // Also count variation selectors (FE0E/FE0F) which add extra tokens
  const emojiPattern =
    /[\u{1F300}-\u{1F9FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}\u{1F600}-\u{1F64F}\u{1F680}-\u{1F6FF}\u{2300}-\u{23FF}\u{2190}-\u{21FF}\u{25A0}-\u{25FF}\u{2B00}-\u{2BFF}]/gu
  const emojiMatches = text.match(emojiPattern) || []
  const emojiCount = emojiMatches.length

  // Count variation selectors (they add extra tokens to base characters)
  const variationSelectorPattern = /[\uFE0E\uFE0F]/g
  const variationMatches = text.match(variationSelectorPattern) || []
  const variationCount = variationMatches.length

  // First, remove code blocks and replace with placeholder to avoid double-counting
  // We'll process them separately
  let workingText = text
  const codeBlockMatches = text.match(/```[\s\S]*?```/g) || []
  const codeBlockLength = codeBlockMatches.reduce((sum, m) => sum + m.length, 0)

  // Remove code blocks from working text for inline code detection
  for (const match of codeBlockMatches) {
    workingText = workingText.replace(match, '')
  }

  // Extract inline code from the remaining text (single backticks)
  const inlineCodeMatches = workingText.match(/`[^`]+`/g) || []
  const inlineCodeLength = inlineCodeMatches.reduce(
    (sum, m) => sum + m.length,
    0,
  )

  // Remaining text (prose) is original length minus code blocks and inline code
  const proseLength = text.length - codeBlockLength - inlineCodeLength

  // Count path-like sequences in prose (consecutive /word patterns)
  // Remove inline code from working text first
  for (const match of inlineCodeMatches) {
    workingText = workingText.replace(match, '')
  }
  const pathMatches = workingText.match(/(?:\/[\w.-]+)+/g) || []
  const pathLength = pathMatches.reduce((sum, m) => sum + m.length, 0)

  // For prose, we need to subtract CJK, emoji, and variation characters since they're counted separately
  const adjustedProseLength = Math.max(
    0,
    proseLength - pathLength - cjkCount - emojiCount - variationCount,
  )

  // Count punctuation in prose (outside code) - these often become separate tokens
  const punctuationMatches =
    workingText.match(/[!?,.:;'"()[\]{}@#$%^&*+=|\\<>~-]/g) || []
  const punctuationCount = punctuationMatches.length

  // Estimate tokens with calibrated ratios:
  // - ASCII prose: ~4.4 chars/token (base rate)
  // - Code blocks: ~3.8 chars/token
  // - Inline code: ~2.5 chars/token (backticks are separate tokens)
  // - Paths: ~3.5 chars/token (slashes are separate tokens)
  // - Punctuation bonus: ~0.5 tokens per punctuation mark
  // - CJK: ~1.2 tokens per character (conservative estimate)
  // - Emojis: ~2.5 tokens per emoji (conservative for compound emojis)
  // - Variation selectors: ~1 token each
  const proseTokens = adjustedProseLength / 4.4
  const codeBlockTokens = codeBlockLength / 3.8
  const inlineCodeTokens = inlineCodeLength / 2.5
  const pathTokens = pathLength / 3.5
  const punctuationBonus = punctuationCount * 0.5
  const cjkTokens = cjkCount * 1.2
  const emojiTokens = emojiCount * 2.5
  const variationTokens = variationCount * 1

  const estimate =
    proseTokens +
    codeBlockTokens +
    inlineCodeTokens +
    pathTokens +
    punctuationBonus +
    cjkTokens +
    emojiTokens +
    variationTokens

  // Add 10% safety margin to avoid under-counting
  return Math.ceil(estimate * 1.1)
}

