            children: [],
            hasCode: false,
            hasList: false,
            hasTable: false,
          },
          {
            heading: 'B',
            level: 2,
            originalTokens: 30,
            summaryTokens: 10,
            summary: 'Content B.',
            children: [],
            hasCode: false,
            hasList: false,
            hasTable: false,
          },
          {
            heading: 'C',
            level: 2,
            originalTokens: 30,
            summaryTokens: 10,
            summary: 'Content C.',
            children: [],
            hasCode: false,
            hasList: false,
            hasTable: false,
          },
        ],
        keyTopics: [],
      }

