      expect(output).toContain('B')
      expect(output).toContain('C')
      expect(countTokensApprox(output)).toBeLessThanOrEqual(100)
    })
  })

  describe('edge cases', () => {
    it('handles empty sections array', () => {
      const mockSummary: DocumentSummary = {
